INSERT INTO "AuditLog" ("id", "userId", "action", "resource", "details", "ip", "createdAt") VALUES ('cmp8i2elf0001l704gbpl6fq5', 'fe776d4a-928c-4cb6-ada8-f70e16a711b5', 'PATCH /api/hero-slides/cmp8b6ayy0001vfp4hd5egl0j', 'hero-slides', '{"image":"https://images.unsplash.com/photo-1530026405186-ed1f139313f8?q=80&w=2000&auto=format&fit=crop","order":3,"titleAr":"علاج العقم والذكورة بالميكروسكوب","titleEn":"Microscopic Infertility & Andrology","isActive":true,"isPortrait":false,"subtitleAr":"حلول علمية متطورة لإعادة الأمل في الإنجاب بأعلى نسب نجاح.","subtitleEn":"Advanced scientific solutions to restore hope with the highest success rates."}', '127.0.0.1', '2026-05-16T15:27:23.235Z');
